import axios from 'axios';
import { env } from './env';
import { getToken, isLoginMode, isTrustedPreview, logout } from '@/lib/auth';

export const apiClient = axios.create({
  baseURL: env.API_BASE_URL,
  timeout: 30_000,
  headers: {
    'Content-Type': 'application/json',
  },
});

function isClientTypeBootstrap(url?: string): boolean {
  return Boolean(url && url.includes('/v2/items/client_type'));
}

apiClient.interceptors.request.use((config) => {
  const headers = (config.headers ??= {} as any) as Record<string, string>;
  headers['Content-Type'] = headers['Content-Type'] || 'application/json';

  if (isLoginMode() && !isTrustedPreview() && !isClientTypeBootstrap(config.url)) {
    const token = getToken();
    if (token) headers.Authorization = `Bearer ${token}`;
    delete headers['X-API-KEY'];
    delete headers['x-api-key'];
    return config;
  }

  headers.Authorization = 'API-KEY';
  if (env.X_API_KEY) headers['X-API-KEY'] = env.X_API_KEY;
  return config;
});

apiClient.interceptors.response.use(
  (response) => response,
  (error) => {
    if (isLoginMode() && !isTrustedPreview() && error?.response?.status === 401) {
      logout();
    }
    return Promise.reject(error);
  }
);

export default apiClient;

const getEnvVar = (key: string, fallback?: string): string => {
  const value = import.meta.env[key] ?? fallback;
  if (value === undefined) {
    console.warn(`[env] Missing environment variable: ${key}`);
    return '';
  }
  return value;
};

