import axios from 'axios';
import { QueryClient } from '@tanstack/react-query';
import { toast } from 'sonner';

export const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 1000 * 60 * 5,
      gcTime: 1000 * 60 * 10,
      retry: (failureCount, error: unknown) => {
        if (axios.isAxiosError(error)) {
          const status = error.response?.status;
          if (status === 401 || status === 403 || status === 404) return false;
        }
        return failureCount < 2;
      },
      refetchOnWindowFocus: false,
    },
    mutations: {
      onError: (error: unknown) => {
        const message = axios.isAxiosError(error)
          ? (error.response?.data?.message ?? 'Что-то пошло не так')
          : 'Что-то пошло не так';
        toast.error(message);
      },
    },
  },
});

import { type ClassValue, clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export function formatDate(
  date: string | Date | null | undefined,
  options: Intl.DateTimeFormatOptions = { day: '2-digit', month: 'short', year: 'numeric' }
): string {
  if (!date) return '—';
  const d = new Date(date);
  if (isNaN(d.getTime())) return '—';
  return new Intl.DateTimeFormat('ru-RU', options).format(d);
}

export function formatCurrency(
  amount: number,
  currency = 'USD',
  locale = 'en-US'
): string {
  return new Intl.NumberFormat(locale, {
    style: 'currency',
    currency,
    minimumFractionDigits: 0,
  }).format(amount);
}

export function formatNumber(value: number, locale = 'en-US'): string {
  return new Intl.NumberFormat(locale).format(value);
}

export function debounce<TArgs extends unknown[]>(
  fn: (...args: TArgs) => void,
  delay: number
): (...args: TArgs) => void {
  let timeout: ReturnType<typeof setTimeout>;
  return (...args: TArgs) => {
    clearTimeout(timeout);
    timeout = setTimeout(() => fn(...args), delay);
  };
}

export function getInitials(name: string | null | undefined): string {
  if (!name) return '?';
  return name.split(' ').slice(0, 2).map((n) => n[0] ?? '').join('').toUpperCase();
}

export function truncate(str: string | null | undefined, maxLength: number): string {
  if (!str) return '';
  if (str.length <= maxLength) return str;
  return str.slice(0, maxLength - 3) + '...';
}

export function generateId(): string {
  return Math.random().toString(36).slice(2, 11);
}

export function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

export function extractList<T>(data: unknown): T[] {
  const r = (data as any)?.data?.data?.response;
  if (Array.isArray(r)) return r;
  if (r && typeof r === 'object') return [r as T];
  return [];
}

export function extractCount(data: unknown): number {
  return (data as any)?.data?.data?.count ?? 0;
}

export function extractSingle<T>(data: unknown): T | null {
  const r = (data as any)?.data?.data?.response;
  if (Array.isArray(r)) return r[0] ?? null;
  return (r as T) ?? null;
}

export function getRelationLabel(value: unknown, labelKey = 'name'): string {
  if (value === null || value === undefined) return '—';
  if (typeof value === 'object') {
    const obj = value as Record<string, unknown>;
    return String(obj[labelKey] ?? obj['id'] ?? '—');
  }
  return String(value);
}

type LoginPayload = Record<string, any>;

export interface CurrentUser {
  user_id?: string;
  role?: unknown;
  client_type?: string;
  login_table_slug?: string;
  user_data?: unknown;
  raw?: unknown;
}

export interface ClientTypeOption {
  guid: string;
  name: string;
  slug?: string;
  [key: string]: unknown;
}

const TOKEN_KEY = 'ucode_admin_access_token';
const USER_KEY = 'ucode_admin_current_user';

let trustedPreview =
  typeof window !== 'undefined' && Boolean(window.__UCODE_PREVIEW_CONTEXT?.trusted);
const previewListeners = new Set<(trusted: boolean) => void>();

const getApiBaseUrl = () =>
  String(import.meta.env.VITE_API_BASE_URL || 'https://admin-api.ucode.run').replace(/\/+$/, '');

const getProjectId = () => String(import.meta.env.VITE_UCODE_PROJECT_ID || '');
const getEnvironmentId = () => String(import.meta.env.VITE_UCODE_ENVIRONMENT_ID || '');
const getApiKey = () => String(import.meta.env.VITE_X_API_KEY || '');

function readNested<T = unknown>(payload: LoginPayload, paths: string[][]): T | undefined {
  for (const path of paths) {
    let value: any = payload;
    for (const key of path) value = value?.[key];
    if (value !== undefined && value !== null) return value as T;
  }
  return undefined;
}

function staticHeaders(): HeadersInit {
  const apiKey = getApiKey();
  return {
    'Content-Type': 'application/json',
    Authorization: 'API-KEY',
    ...(apiKey ? { 'X-API-KEY': apiKey } : {}),
  };
}

async function requestJson<T>(path: string, init: RequestInit): Promise<T> {
  const response = await fetch(`${getApiBaseUrl()}${path}`, init);
  const contentType = response.headers.get('content-type') || '';
  const payload = contentType.includes('application/json')
    ? await response.json()
    : await response.text();

  if (!response.ok) {
    const message =
      typeof payload === 'object' && payload !== null
        ? (payload as any).message || (payload as any).error
        : payload;
    throw new Error(String(message || `Request failed with ${response.status}`));
  }

  return payload as T;
}

export function isLoginMode(): boolean {
  return import.meta.env.VITE_UCODE_AUTH_MODE === 'login';
}

export function isTrustedPreview(): boolean {
  if (typeof window === 'undefined') return false;
  return trustedPreview || Boolean(window.__UCODE_PREVIEW_CONTEXT?.trusted);
}

export function subscribePreviewContext(listener: (trusted: boolean) => void): () => void {
  previewListeners.add(listener);
  listener(isTrustedPreview());
  return () => previewListeners.delete(listener);
}

function applyPreviewTrusted(next: boolean) {
  trustedPreview = next;
  previewListeners.forEach((listener) => listener(trustedPreview));
}

if (typeof window !== 'undefined') {
  window.addEventListener('message', (event: MessageEvent) => {
    if (event?.data?.type === 'UCODE_PREVIEW_CONTEXT') {
      applyPreviewTrusted(Boolean(event.data.trusted));
    }
  });
}

export function getToken(): string | null {
  if (typeof window === 'undefined') return null;
  return sessionStorage.getItem(TOKEN_KEY);
}

export function setToken(token: string): void {
  if (typeof window === 'undefined') return;
  sessionStorage.setItem(TOKEN_KEY, token);
}

export function logout(): void {
  if (typeof window !== 'undefined') {
    sessionStorage.removeItem(TOKEN_KEY);
    sessionStorage.removeItem(USER_KEY);
    window.location.assign('/login');
  }
}

export function getCurrentUser(): CurrentUser | null {
  if (typeof window === 'undefined') return null;
  try {
    const raw = sessionStorage.getItem(USER_KEY);
    return raw ? (JSON.parse(raw) as CurrentUser) : null;
  } catch {
    return null;
  }
}

export async function fetchClientTypes(): Promise<ClientTypeOption[]> {
  const payload = await requestJson<LoginPayload>('/v2/items/client_type', {
    method: 'GET',
    headers: staticHeaders(),
  });

  const raw =
    readNested<unknown>(payload, [
      ['data', 'data', 'response'],
      ['data', 'response'],
      ['response'],
      ['data'],
    ]) ?? [];
  const list = Array.isArray(raw) ? raw : raw ? [raw] : [];

  return list
    .map((item: any) => ({
      ...item,
      guid: String(item?.guid || item?.id || item?.value || ''),
      name: String(item?.name || item?.title || item?.label || item?.client_type || 'Client type'),
      slug: item?.slug,
    }))
    .filter((item) => item.guid);
}

export async function login(username: string, password: string, clientType: string) {
  const payload = await requestJson<LoginPayload>('/v2/login', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Environment-Id': getEnvironmentId(),
    },
    body: JSON.stringify({
      username,
      password,
      client_type: clientType,
      project_id: getProjectId(),
      type: 'default',
    }),
  });

  const token = readNested<string>(payload, [
    ['data', 'token', 'access_token'],
    ['data', 'data', 'token', 'access_token'],
    ['token', 'access_token'],
    ['access_token'],
  ]);

  if (!token) {
    throw new Error('Login response did not include an access token');
  }

  const data = (payload.data ?? payload) as LoginPayload;
  const user: CurrentUser = {
    user_id: data.user_id,
    role: data.role,
    client_type: data.client_type ?? clientType,
    login_table_slug: data.login_table_slug,
    user_data: data.user_data,
    raw: data,
  };

  setToken(token);
  if (typeof window !== 'undefined') {
    sessionStorage.setItem(USER_KEY, JSON.stringify(user));
  }

  return { token, user, raw: payload };
}

declare global {
  interface Window {
    __UCODE_PREVIEW_CONTEXT?: { trusted?: boolean };
  }
}

import { useEffect, useState } from 'react';
import { getToken, isTrustedPreview } from '@/lib/auth';

export type PermFlags = { read?: boolean; write?: boolean; update?: boolean; delete?: boolean };
export type PermMap = Record<string, PermFlags>;

type PermListener = (map: PermMap) => void;
type ReadyListener = (ready: boolean) => void;

function parseEnvPerms(): PermMap {
  try {
    return JSON.parse(import.meta.env.VITE_UCODE_PERMISSIONS || '{}') as PermMap;
  } catch {
    return {};
  }
}

const initial = parseEnvPerms();
let current: PermMap = initial;
let loaded = Object.keys(initial).length > 0;
const listeners = new Set<PermListener>();
const readyListeners = new Set<ReadyListener>();

function normalizePath(path: string): string {
  if (!path) return '/';
  if (path === '/') return path;
  return path.startsWith('/') ? path : `/${path}`;
}

function notify() {
  listeners.forEach((fn) => fn(current));
  readyListeners.forEach((fn) => fn(loaded));
}

function applyPerms(next: PermMap, ready = true) {
  current = next || {};
  loaded = ready;
  notify();
}

if (typeof window !== 'undefined') {
  window.addEventListener('message', (event: MessageEvent) => {
    if (event?.data?.type === 'UCODE_PERMISSIONS' && event.data.permissions) {
      applyPerms(event.data.permissions as PermMap, true);
    }
  });
}

export function setUcodePermissions(next: PermMap): void {
  applyPerms(next, true);
}

export function resetUcodePermissions(): void {
  applyPerms({}, false);
}

export function useUcodePermissions(): PermMap {
  const [map, setMap] = useState<PermMap>(current);
  useEffect(() => {
    listeners.add(setMap);
    setMap(current);
    return () => {
      listeners.delete(setMap);
    };
  }, []);
  return map;
}

export function useUcodePermissionsReady(): boolean {
  const [ready, setReady] = useState<boolean>(loaded);
  useEffect(() => {
    readyListeners.add(setReady);
    setReady(loaded);
    return () => {
      readyListeners.delete(setReady);
    };
  }, []);
  return ready;
}

const isLoginMode = import.meta.env.VITE_UCODE_AUTH_MODE === 'login';

export function canRead(perms: PermMap, path: string): boolean {
  const normalized = normalizePath(path);
  const entry = perms[normalized] ?? perms[path];
  if (entry) return entry.read !== false;
  if (isLoginMode && isTrustedPreview() && !loaded) return true;
  return !isLoginMode;
}

function apiBaseUrl(): string {
  return String(import.meta.env.VITE_API_BASE_URL || 'https://admin-api.ucode.run').replace(/\/+$/, '');
}

function extractPermMap(payload: any): PermMap {
  const raw =
    payload?.data?.permissions ??
    payload?.data?.nav_map ??
    payload?.data?.data?.permissions ??
    payload?.data?.data?.nav_map ??
    payload?.permissions ??
    payload?.nav_map ??
    payload?.data ??
    payload;
  return raw && typeof raw === 'object' && !Array.isArray(raw) ? (raw as PermMap) : {};
}

export async function initNavMapFromAuth(token = getToken()): Promise<PermMap> {
  if (!token) {
    resetUcodePermissions();
    return {};
  }

  const response = await fetch(`${apiBaseUrl()}/v2/custom-permission/nav-map`, {
    method: 'GET',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${token}`,
      'Environment-Id': String(import.meta.env.VITE_UCODE_ENVIRONMENT_ID || ''),
    },
  });

  const payload = await response.json().catch(() => ({}));
  if (!response.ok) {
    throw new Error(payload?.message || payload?.error || `Permission map failed with ${response.status}`);
  }

  const permissions = extractPermMap(payload);
  setUcodePermissions(permissions);
  return permissions;
}

