import { FormEvent, useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  fetchClientTypes,
  getToken,
  isTrustedPreview,
  login,
  type ClientTypeOption,
} from '@/lib/auth';
import { initNavMapFromAuth } from '@/lib/permissions';

type LoginPageProps = {
  onSuccess?: () => void;
};

export function LoginPage({ onSuccess }: LoginPageProps) {
  const navigate = useNavigate();
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [clientTypes, setClientTypes] = useState<ClientTypeOption[]>([]);
  const [clientType, setClientType] = useState('');
  const [loadingClientTypes, setLoadingClientTypes] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    if (isTrustedPreview()) {
      onSuccess?.();
      navigate('/', { replace: true });
      return;
    }

    if (getToken()) {
      onSuccess?.();
      navigate('/', { replace: true });
      return;
    }

    let cancelled = false;
    setLoadingClientTypes(true);
    fetchClientTypes()
      .then((items) => {
        if (cancelled) return;
        setClientTypes(items);
        if (items.length === 1) setClientType(items[0].guid);
      })
      .catch((err) => {
        if (!cancelled) setError(err instanceof Error ? err.message : 'Failed to load client types');
      })
      .finally(() => {
        if (!cancelled) setLoadingClientTypes(false);
      });

    return () => {
      cancelled = true;
    };
  }, [navigate, onSuccess]);

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setError('');

    if (clientTypes.length > 0 && !clientType) {
      setError('Choose a client type');
      return;
    }

    setSubmitting(true);
    try {
      const result = await login(username.trim(), password, clientType);
      await initNavMapFromAuth(result.token);
      onSuccess?.();
      navigate('/', { replace: true });
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Login failed');
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <div className="min-h-screen bg-background text-foreground flex items-center justify-center px-4 py-10">
      <div className="w-full max-w-md rounded-lg border border-border bg-card p-6 shadow-sm">
        <div className="mb-6 space-y-2">
          <h1 className="text-2xl font-semibold tracking-normal">Sign in</h1>
          <p className="text-sm text-muted-foreground">Use your project account to open this admin panel.</p>
        </div>

        <form className="space-y-4" onSubmit={handleSubmit}>
          <label className="block space-y-2">
            <span className="text-sm font-medium">Login</span>
            <input
              className="h-10 w-full rounded-md border border-input bg-background px-3 text-sm outline-none transition-colors focus:border-ring focus:ring-2 focus:ring-ring/40"
              value={username}
              onChange={(event) => setUsername(event.target.value)}
              autoComplete="username"
              required
            />
          </label>

          <label className="block space-y-2">
            <span className="text-sm font-medium">Password</span>
            <input
              className="h-10 w-full rounded-md border border-input bg-background px-3 text-sm outline-none transition-colors focus:border-ring focus:ring-2 focus:ring-ring/40"
              value={password}
              onChange={(event) => setPassword(event.target.value)}
              type="password"
              autoComplete="current-password"
              required
            />
          </label>

          {clientTypes.length > 1 && (
            <div className="space-y-2">
              <span className="text-sm font-medium">Client type</span>
              <div className="grid gap-2">
                {clientTypes.map((item) => (
                  <button
                    key={item.guid}
                    type="button"
                    className={
                      clientType === item.guid
                        ? 'h-10 rounded-md border border-primary bg-primary text-primary-foreground px-3 text-left text-sm transition-colors'
                        : 'h-10 rounded-md border border-input bg-background px-3 text-left text-sm transition-colors hover:bg-accent hover:text-accent-foreground'
                    }
                    onClick={() => setClientType(item.guid)}
                  >
                    {item.name}
                  </button>
                ))}
              </div>
            </div>
          )}

          {error && (
            <div className="rounded-md border border-destructive/30 bg-destructive/10 px-3 py-2 text-sm text-destructive">
              {error}
            </div>
          )}

          <button
            className="h-10 w-full rounded-md bg-primary px-4 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90 disabled:cursor-not-allowed disabled:opacity-60"
            type="submit"
            disabled={submitting || loadingClientTypes}
          >
            {submitting ? 'Signing in...' : loadingClientTypes ? 'Preparing...' : 'Sign in'}
          </button>
        </form>
      </div>
    </div>
  );
}

import { ReactNode, useEffect, useState } from 'react';
import { getToken, isLoginMode, isTrustedPreview, logout, subscribePreviewContext } from '@/lib/auth';
import { initNavMapFromAuth } from '@/lib/permissions';
import { LoginPage } from './LoginPage';

type ProtectedRouteProps = {
  children: ReactNode;
};

export function ProtectedRoute({ children }: ProtectedRouteProps) {
  const [trustedPreview, setTrustedPreview] = useState(isTrustedPreview());
  const [sessionVersion, setSessionVersion] = useState(0);
  const [ready, setReady] = useState(!isLoginMode() || trustedPreview);
  const [error, setError] = useState('');
  const token = getToken();

  useEffect(() => subscribePreviewContext(setTrustedPreview), []);

  useEffect(() => {
    if (!isLoginMode() || trustedPreview) {
      setReady(true);
      return;
    }

    if (!token) {
      setReady(false);
      return;
    }

    let cancelled = false;
    setReady(false);
    setError('');

    initNavMapFromAuth(token)
      .then(() => {
        if (!cancelled) setReady(true);
      })
      .catch((err) => {
        if (!cancelled) {
          setError(err instanceof Error ? err.message : 'Failed to load permissions');
          setReady(false);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [token, sessionVersion, trustedPreview]);

  if (!isLoginMode() || trustedPreview) {
    return <>{children}</>;
  }

  if (!token) {
    return <LoginPage onSuccess={() => setSessionVersion((value) => value + 1)} />;
  }

  if (error) {
    return (
      <div className="min-h-screen bg-background text-foreground flex items-center justify-center px-4">
        <div className="w-full max-w-md rounded-lg border border-border bg-card p-6 shadow-sm">
          <h1 className="text-xl font-semibold tracking-normal">Permissions unavailable</h1>
          <p className="mt-2 text-sm text-muted-foreground">{error}</p>
          <div className="mt-5 flex gap-2">
            <button
              type="button"
              className="h-10 rounded-md bg-primary px-4 text-sm font-medium text-primary-foreground hover:bg-primary/90"
              onClick={() => setSessionVersion((value) => value + 1)}
            >
              Retry
            </button>
            <button
              type="button"
              className="h-10 rounded-md border border-input bg-background px-4 text-sm font-medium hover:bg-accent hover:text-accent-foreground"
              onClick={logout}
            >
              Sign out
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (!ready) {
    return (
      <div className="flex min-h-screen w-full items-center justify-center bg-background text-foreground">
        <div className="h-10 w-10 animate-spin rounded-full border-4 border-muted border-t-primary" />
      </div>
    );
  }

  return <>{children}</>;
}
